"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { triggerShake, getRandomComplete } from "@/lib/learningMessages";

// ===== 形状定义（12格面积）=====
const ROWS = 6;
const COLS = 8;

type Phase = "guided" | "guidedQuestion" | "guidedResult" | "free" | "reflect" | "done";

// 三个预设形状的格子坐标
const SHAPES: { name: string; cells: [number, number][] }[] = [
  {
    name: "直条形",
    cells: Array.from({ length: 12 }, (_, i) => [Math.floor(i / 4), i % 4] as [number, number]),
  },
  {
    name: "L形",
    cells: [
      [0, 0], [1, 0], [2, 0], [3, 0],
      [0, 1], [1, 1], [2, 1], [3, 1],
      [4, 0], [4, 1], [5, 0], [5, 1],
    ],
  },
  {
    name: "阶梯形",
    cells: [
      [0, 0], [0, 1],
      [1, 0], [1, 1], [1, 2],
      [2, 0], [2, 1], [2, 2], [2, 3],
      [3, 0], [3, 1], [3, 2],
    ],
  },
];

// 自由探索网格
const FREE_ROWS = 6;
const FREE_COLS = 8;

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("guided");
  const [activeShape, setActiveShape] = useState(0);
  const [revealedShapes, setRevealedShapes] = useState<boolean[]>([false, false, false]);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [freeGrid, setFreeGrid] = useState<boolean[][]>(
    Array.from({ length: FREE_ROWS }, () => Array(FREE_COLS).fill(false))
  );
  const [discoveries, setDiscoveries] = useState<number>(0);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const freeCount = freeGrid.flat().filter(Boolean).length;

  const handleShapeClick = (idx: number) => {
    setActiveShape(idx);
    if (!revealedShapes[idx]) {
      // 逐步揭示格子
      const cells = SHAPES[idx].cells;
      cells.forEach((cell, i) => {
        setTimeout(() => {
          setRevealedShapes((prev) => {
            const next = [...prev];
            next[idx] = true;
            return next;
          });
        }, i * 150);
      });
    }
  };

  const handleGuidedAnswer = (answer: number) => {
    setSelectedAnswer(answer);
    if (answer === 1) {
      // B. 面积一样
      setPhase("guidedResult");
    } else {
      const qEl = document.getElementById("guided-question");
      triggerShake(qEl);
    }
  };

  const toggleCell = (r: number, c: number) => {
    setFreeGrid((prev) => {
      const next = prev.map((row) => [...row]);
      next[r][c] = !next[r][c];
      return next;
    });
  };

  const handleFreeCheck = () => {
    if (freeCount === 12 && freeCount > 0) {
      setDiscoveries((prev) => prev + 1);
      // 清空网格供下一次探索
      setFreeGrid(Array.from({ length: FREE_ROWS }, () => Array(FREE_COLS).fill(false)));
    }
  };

  const handleReflectAnswer = (answer: number) => {
    if (answer === 1) {
      setPhase("done");
    } else {
      const qEl = document.getElementById("reflect-question");
      triggerShake(qEl);
    }
  };

  const nextStep = getNextStep("area", "transform");

  return (
    <StepShell topicId="area" stepId="transform">
      {/* ===== 第一阶段：引导验证 ===== */}
      {phase === "guided" || phase === "guidedQuestion" || phase === "guidedResult" ? (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
              这三个形状都用 12 个格子拼成，点击看看它们长什么样
            </p>

            {/* 三个形状并排 */}
            <div className="grid grid-cols-3 gap-4">
              {SHAPES.map((shape, idx) => (
                <div key={idx} className="flex flex-col items-center gap-2">
                  <button
                    onClick={() => handleShapeClick(idx)}
                    className={`rounded-lg p-2 transition-all ${
                      activeShape === idx
                        ? "ring-2 ring-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                        : "border border-[var(--border)] hover:border-[var(--primary-light)]"
                    }`}
                  >
                    <div
                      className="relative"
                      style={{
                        width: COLS * 22,
                        height: ROWS * 22,
                      }}
                    >
                      {/* 灰色虚线底格 */}
                      {Array.from({ length: ROWS }).map((_, r) =>
                        Array.from({ length: COLS }).map((_, c) => (
                          <div
                            key={`${r}-${c}`}
                            className="absolute rounded-sm"
                            style={{
                              top: r * 22,
                              left: c * 22,
                              width: 20,
                              height: 20,
                              border: "1px dashed var(--signal-pending)",
                              opacity: 0.2,
                            }}
                          />
                        ))
                      )}
                      {/* 形状格子 */}
                      {revealedShapes[idx] &&
                        shape.cells.map(([r, c], i) => (
                          <div
                            key={i}
                            className="absolute rounded-sm animate-float-in"
                            style={{
                              top: r * 22,
                              left: c * 22,
                              width: 20,
                              height: 20,
                              backgroundColor: "var(--signal-confirmed)",
                              opacity: 0.8,
                              border: "1px solid rgba(255,255,255,0.5)",
                            }}
                          />
                        ))}
                    </div>
                  </button>
                  <span className="text-xs font-medium text-[var(--text)]">
                    {shape.name}
                  </span>
                  {revealedShapes[idx] && (
                    <span className="text-xs text-[var(--signal-success)]">
                      面积 = 12 ✓
                    </span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* 全部揭示后显示问题 */}
          {revealedShapes.every(Boolean) && phase === "guided" && (
            <div className="flex justify-center animate-float-in">
              <button
                onClick={() => setPhase("guidedQuestion")}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                这三个形状有什么一样的地方？→
              </button>
            </div>
          )}

          {/* 问题 */}
          {phase === "guidedQuestion" && (
            <div
              id="guided-question"
              className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
            >
              <p className="mb-4 text-center text-[var(--text)] font-medium">
                这三个形状有什么一样的地方？
              </p>
              <div className="grid grid-cols-1 gap-3">
                {[
                  { label: "A. 周长一样", value: 0 },
                  { label: "B. 面积一样", value: 1 },
                  { label: "C. 形状一样", value: 2 },
                ].map((opt) => (
                  <button
                    key={opt.value}
                    onClick={() => handleGuidedAnswer(opt.value)}
                    className={`rounded-lg border px-4 py-3 text-sm font-medium transition-all hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10 ${
                      selectedAnswer === opt.value
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* 引导结果 */}
          {phase === "guidedResult" && (
            <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
              <div className="text-3xl mb-2">🎉</div>
              <p className="text-lg font-semibold text-[var(--text)]">
                不同形状可以面积相同，这三个形状的面积都是 12 格！
              </p>
              <div className="mt-4 flex justify-center gap-6">
                {SHAPES.map((shape, idx) => (
                  <div key={idx} className="flex flex-col items-center gap-1">
                    <div
                      className="relative animate-pulse-highlight rounded p-1"
                      style={{ width: COLS * 18, height: ROWS * 18 }}
                    >
                      {shape.cells.map(([r, c], i) => (
                        <div
                          key={i}
                          className="absolute rounded-sm"
                          style={{
                            top: r * 18,
                            left: c * 18,
                            width: 16,
                            height: 16,
                            backgroundColor: "var(--signal-confirmed)",
                            opacity: 0.8,
                          }}
                        />
                      ))}
                    </div>
                    <span className="text-xs text-[var(--text-muted)]">12 格</span>
                  </div>
                ))}
              </div>
              <div className="mt-6">
                <button
                  onClick={() => setPhase("free")}
                  className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  试试自己拼一个 →
                </button>
              </div>
            </div>
          )}
        </div>
      ) : null}

      {/* ===== 第二阶段：自由探索 ===== */}
      {phase === "free" && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <p className="mb-2 text-center text-[var(--text)] font-medium">
              你能拼出面积 = 12 但不一样的形状吗？
            </p>
            <p className="mb-4 text-center text-xs text-[var(--text-muted)]">
              点击格子填充/取消，实时显示面积
            </p>

            {/* 自由网格 */}
            <div className="flex justify-center">
              <div
                className="grid gap-0.5"
                style={{
                  gridTemplateColumns: `repeat(${FREE_COLS}, 36px)`,
                }}
              >
                {freeGrid.map((row, r) =>
                  row.map((filled, c) => (
                    <div
                      key={`${r}-${c}`}
                      onClick={() => toggleCell(r, c)}
                      className="rounded-sm cursor-pointer transition-all"
                      style={{
                        width: 36,
                        height: 36,
                        border: "2px dashed var(--signal-pending)",
                        opacity: filled ? 1 : 0.3,
                        backgroundColor: filled ? "var(--signal-confirmed)" : "transparent",
                      }}
                    />
                  ))
                )}
              </div>
            </div>

            {/* 实时面积 */}
            <div className="mt-4 text-center">
              <span
                className={`inline-block rounded-full px-6 py-2 font-bold text-lg ${
                  freeCount === 12
                    ? "bg-[var(--signal-success)] text-white animate-pulse-highlight"
                    : "bg-[var(--bg-soft)] text-[var(--text)]"
                }`}
              >
                面积 = {freeCount}
              </span>
              {freeCount === 12 && (
                <p className="mt-2 text-sm text-[var(--signal-success)] animate-float-in">
                  ✓ 找到了！面积 = 12 的新形状！
                </p>
              )}
            </div>

            {/* 操作按钮 */}
            <div className="mt-4 flex justify-center gap-3">
              <button
                onClick={() => setFreeGrid(Array.from({ length: FREE_ROWS }, () => Array(FREE_COLS).fill(false)))}
                className="rounded-full border border-[var(--border)] px-4 py-2 text-sm text-[var(--text-secondary)] hover:bg-[var(--bg-soft)]"
              >
                清空
              </button>
              <button
                onClick={handleFreeCheck}
                disabled={freeCount !== 12}
                className="rounded-full px-4 py-2 text-sm font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105 disabled:opacity-30"
                style={{ backgroundColor: "var(--accent)" }}
              >
                收入发现集
              </button>
            </div>

            {/* 发现集 */}
            <div className="mt-4 text-center">
              <span className="text-sm text-[var(--text-secondary)]">
                📒 我的发现集：已发现 <strong className="text-[var(--accent-dark)]">{discoveries}</strong> 个面积=12的形状
              </span>
            </div>
          </div>

          <div className="flex justify-center">
            <button
              onClick={() => setPhase("reflect")}
              className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
            >
              想一想 →
            </button>
          </div>
        </div>
      )}

      {/* ===== 反思阶段 ===== */}
      {phase === "reflect" && (
        <div
          id="reflect-question"
          className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
        >
          <p className="mb-4 text-center text-[var(--text)] font-medium">
            形状在变，什么没变？
          </p>
          <div className="grid grid-cols-1 gap-3">
            {[
              { label: "A. 周长没变", value: 0 },
              { label: "B. 面积没变", value: 1 },
              { label: "C. 形状没变", value: 2 },
            ].map((opt) => (
              <button
                key={opt.value}
                onClick={() => handleReflectAnswer(opt.value)}
                className="rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3 text-sm font-medium transition-all hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10"
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* ===== 完成阶段 ===== */}
      {phase === "done" && (
        <div className="space-y-4">
          <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
            <div className="text-4xl mb-2">🌟</div>
            <p className="text-lg font-semibold text-[var(--text)]">{completeMsg}</p>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你发现了一个重要规律：形状可以变，但面积不变！
            </p>
          </div>

          <div className="flex justify-center gap-4">
            <button
              onClick={() => {
                setPhase("guided");
                setRevealedShapes([false, false, false]);
                setSelectedAnswer(null);
                setFreeGrid(Array.from({ length: FREE_ROWS }, () => Array(FREE_COLS).fill(false)));
                setDiscoveries(0);
              }}
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] hover:bg-[var(--bg-soft)]"
            >
              再玩一次
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
